mapper.sql:
SELECT CONCAT('xm_video_task:', vt.task_id) AS record_id, CAST(vt.user_id AS CHAR) AS user_id, 'video' AS result_type, vt.task_type AS source_type, 'xm_video_task' AS source_table, vt.task_id AS source_result_id, vt.source_session_id AS source_session_id, vt.task_state AS status, vt.summary AS display_title, COALESCE(vt.error_summary, vt.summary) AS summary, COALESCE(vt.detail_ref, vt.replay_hint, vt.result_ref, vt.source_artifact_ref) AS detail_ref, COALESCE(vt.complete_time, vt.fail_time, vt.update_time, vt.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_video_task vt LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(vt.user_id AS CHAR) AND rec.source_table = 'xm_video_task' AND rec.source_result_id = vt.task_id LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(vt.user_id AS CHAR) AND fav.source_table = 'xm_video_task' AND fav.source_result_id = vt.task_id AND fav.active_flag = '1'
AND vt.user_id = #{query.userId}
AND vt.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_classroom_session:', cs.task_id) AS record_id, CAST(cs.user_id AS CHAR) AS user_id, 'classroom' AS result_type, cs.task_type AS source_type, 'xm_classroom_session' AS source_table, cs.task_id AS source_result_id, cs.source_session_id AS source_session_id, cs.task_state AS status, cs.summary AS display_title, COALESCE(cs.error_summary, cs.summary) AS summary, COALESCE(cs.detail_ref, cs.replay_hint, cs.result_ref, cs.source_artifact_ref) AS detail_ref, COALESCE(cs.complete_time, cs.fail_time, cs.update_time, cs.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_classroom_session cs LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(cs.user_id AS CHAR) AND rec.source_table = 'xm_classroom_session' AND rec.source_result_id = cs.task_id LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(cs.user_id AS CHAR) AND fav.source_table = 'xm_classroom_session' AND fav.source_result_id = cs.task_id AND fav.active_flag = '1'
AND cs.user_id = #{query.userId}
AND cs.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_companion_turn:', ct.turn_id) AS record_id, CAST(ct.user_id AS CHAR) AS user_id, 'companion' AS result_type, ct.context_type AS source_type, 'xm_companion_turn' AS source_table, ct.turn_id AS source_result_id, ct.session_id AS source_session_id, ct.persistence_status AS status, LEFT(ct.question_text, 255) AS display_title, LEFT(ct.answer_summary, 1000) AS summary, COALESCE(ct.anchor_ref, ct.session_id) AS detail_ref, ct.turn_time AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_companion_turn ct LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(ct.user_id AS CHAR) AND rec.source_table = 'xm_companion_turn' AND rec.source_result_id = ct.turn_id LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(ct.user_id AS CHAR) AND fav.source_table = 'xm_companion_turn' AND fav.source_result_id = ct.turn_id AND fav.active_flag = '1'
AND ct.user_id = #{query.userId}
AND ct.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_knowledge_chat_log:', kg.chat_log_id) AS record_id, CAST(kg.user_id AS CHAR) AS user_id, 'evidence' AS result_type, kg.context_type AS source_type, 'xm_knowledge_chat_log' AS source_table, kg.chat_log_id AS source_result_id, kg.session_id AS source_session_id, kg.persistence_status AS status, LEFT(kg.question_text, 255) AS display_title, LEFT(kg.answer_summary, 1000) AS summary, COALESCE(kg.anchor_ref, kg.session_id) AS detail_ref, kg.chat_time AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_knowledge_chat_log kg LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(kg.user_id AS CHAR) AND rec.source_table = 'xm_knowledge_chat_log' AND rec.source_result_id = kg.chat_log_id LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(kg.user_id AS CHAR) AND fav.source_table = 'xm_knowledge_chat_log' AND fav.source_result_id = kg.chat_log_id AND fav.active_flag = '1'
AND kg.user_id = #{query.userId}
AND kg.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_learning_record:', CAST(lr.record_id AS CHAR)) AS record_id, CAST(lr.user_id AS CHAR) AS user_id, lr.result_type AS result_type, lr.source_type AS source_type, 'xm_learning_record' AS source_table, COALESCE(lr.source_result_id, CAST(lr.record_id AS CHAR)) AS source_result_id, lr.source_session_id AS source_session_id, lr.status AS status, COALESCE( lr.display_title, CASE lr.result_type WHEN 'checkpoint' THEN '学习起点 / checkpoint' WHEN 'quiz' THEN '测验结果' WHEN 'wrongbook' THEN '错题本' WHEN 'recommendation' THEN '知识推荐' WHEN 'path' THEN '学习路径' ELSE CONCAT('学习记录 / ', lr.result_type) END ) AS display_title, lr.analysis_summary AS summary, lr.detail_ref AS detail_ref, COALESCE(lr.source_time, lr.update_time, lr.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(lr.deleted_flag, '0') AS deleted_flag FROM xm_learning_record lr LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(lr.user_id AS CHAR) AND fav.source_table = 'xm_learning_record' AND fav.source_result_id = COALESCE(lr.source_result_id, CAST(lr.record_id AS CHAR)) AND fav.active_flag = '1'
AND lr.source_table = 'xm_learning_record' AND lr.result_type = 'checkpoint'
AND lr.user_id = #{query.userId}
AND lr.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_quiz_result:', CAST(qr.quiz_result_id AS CHAR)) AS record_id, CAST(qr.user_id AS CHAR) AS user_id, 'quiz' AS result_type, qr.source_type AS source_type, 'xm_quiz_result' AS source_table, COALESCE(qr.source_result_id, CAST(qr.quiz_result_id AS CHAR)) AS source_result_id, qr.source_session_id AS source_session_id, qr.status AS status, '测验结果' AS display_title, qr.analysis_summary AS summary, qr.detail_ref AS detail_ref, COALESCE(qr.source_time, qr.update_time, qr.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_quiz_result qr LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(qr.user_id AS CHAR) AND rec.source_table = 'xm_quiz_result' AND rec.source_result_id = COALESCE(qr.source_result_id, CAST(qr.quiz_result_id AS CHAR)) LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(qr.user_id AS CHAR) AND fav.source_table = 'xm_quiz_result' AND fav.source_result_id = COALESCE(qr.source_result_id, CAST(qr.quiz_result_id AS CHAR)) AND fav.active_flag = '1'
AND qr.user_id = #{query.userId}
AND qr.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_learning_wrongbook:', CAST(wb.wrongbook_id AS CHAR)) AS record_id, CAST(wb.user_id AS CHAR) AS user_id, 'wrongbook' AS result_type, wb.source_type AS source_type, 'xm_learning_wrongbook' AS source_table, COALESCE(wb.source_result_id, CAST(wb.wrongbook_id AS CHAR)) AS source_result_id, wb.source_session_id AS source_session_id, wb.status AS status, '错题本' AS display_title, wb.analysis_summary AS summary, wb.detail_ref AS detail_ref, COALESCE(wb.source_time, wb.update_time, wb.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_learning_wrongbook wb LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(wb.user_id AS CHAR) AND rec.source_table = 'xm_learning_wrongbook' AND rec.source_result_id = COALESCE(wb.source_result_id, CAST(wb.wrongbook_id AS CHAR)) LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(wb.user_id AS CHAR) AND fav.source_table = 'xm_learning_wrongbook' AND fav.source_result_id = COALESCE(wb.source_result_id, CAST(wb.wrongbook_id AS CHAR)) AND fav.active_flag = '1'
AND wb.user_id = #{query.userId}
AND wb.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_learning_recommendation:', CAST(lr2.recommendation_id AS CHAR)) AS record_id, CAST(lr2.user_id AS CHAR) AS user_id, 'recommendation' AS result_type, lr2.source_type AS source_type, 'xm_learning_recommendation' AS source_table, COALESCE(lr2.source_result_id, CAST(lr2.recommendation_id AS CHAR)) AS source_result_id, lr2.source_session_id AS source_session_id, lr2.status AS status, '知识推荐' AS display_title, lr2.recommendation_reason AS summary, lr2.detail_ref AS detail_ref, COALESCE(lr2.source_time, lr2.update_time, lr2.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_learning_recommendation lr2 LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(lr2.user_id AS CHAR) AND rec.source_table = 'xm_learning_recommendation' AND rec.source_result_id = COALESCE(lr2.source_result_id, CAST(lr2.recommendation_id AS CHAR)) LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(lr2.user_id AS CHAR) AND fav.source_table = 'xm_learning_recommendation' AND fav.source_result_id = COALESCE(lr2.source_result_id, CAST(lr2.recommendation_id AS CHAR)) AND fav.active_flag = '1'
AND lr2.user_id = #{query.userId}
AND lr2.user_id = #{userId}
UNION ALL
SELECT CONCAT('xm_learning_path:', CAST(lp.path_id AS CHAR)) AS record_id, CAST(lp.user_id AS CHAR) AS user_id, 'path' AS result_type, lp.source_type AS source_type, 'xm_learning_path' AS source_table, COALESCE(lp.source_result_id, CAST(lp.path_id AS CHAR)) AS source_result_id, lp.source_session_id AS source_session_id, lp.status AS status, '学习路径' AS display_title, lp.path_summary AS summary, lp.detail_ref AS detail_ref, COALESCE(lp.source_time, lp.update_time, lp.create_time) AS source_time, CASE WHEN fav.active_flag = '1' THEN TRUE ELSE FALSE END AS favorite, fav.favorite_time AS favorite_time, COALESCE(rec.deleted_flag, '0') AS deleted_flag FROM xm_learning_path lp LEFT JOIN xm_learning_record rec ON rec.user_id = CAST(lp.user_id AS CHAR) AND rec.source_table = 'xm_learning_path' AND rec.source_result_id = COALESCE(lp.source_result_id, CAST(lp.path_id AS CHAR)) LEFT JOIN xm_learning_favorite fav ON fav.user_id = CAST(lp.user_id AS CHAR) AND fav.source_table = 'xm_learning_path' AND fav.source_result_id = COALESCE(lp.source_result_id, CAST(lp.path_id AS CHAR)) AND fav.active_flag = '1'
AND lp.user_id = #{query.userId}
AND lp.user_id = #{userId}

